module adder_4bit (alt_A, B, CIN, SUM, COUT);
input alt_A;
input B;
input CIN;
output SUM;
output COUT;

assign {COUT, SUM} = alt_A + B + CIN;

endmodule

module adder_4bit (alt_A, B, CIN, SUM, COUT);
input [3:0] alt_A;
input [3:0] B;
input CIN;
output [3:0] SUM;
output COUT;

wire C1, C2, C3;

full_adder fa0 (alt_A[0], B[0], CIN, SUM[0], C1);
full_adder fa1 (alt_A[1], B[1], C1, SUM[1], C2);
full_adder fa2 (alt_A[2], B[2], C2, SUM[2], C3);
full_adder fa3 (alt_A[3], B[3], C3, SUM[3], COUT);

endmodule
